import {
  PinInput as PinInputPrimitive,
  usePinInput as usePinInputPrimitive,
  usePinInputContext,
  type UsePinInputProps,
} from '@ark-ui/react/pin-input';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef, ReactElement, ReactNode } from 'react';
import { Children, cloneElement, forwardRef } from 'react';
import { SeparatorMarkIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './PinInput.module.css';

const PinInputRoot = forwardRef<
  ComponentRef<typeof PinInputPrimitive.Root>,
  ComponentProps<typeof PinInputPrimitive.Root>
>(function PinInputRoot({ asChild, children, className, count, placeholder = '', ...props }, ref) {
  return (
    <PinInputPrimitive.Root
      ref={ref}
      asChild={asChild}
      data-slot="pin-input-root"
      className={clsx(styles.root, normalizeClassName(className))}
      count={count}
      placeholder={placeholder}
      {...props}
    >
      {withHiddenInput(children, asChild)}
    </PinInputPrimitive.Root>
  );
});

const PinInputRootProvider = forwardRef<
  ComponentRef<typeof PinInputPrimitive.RootProvider>,
  ComponentProps<typeof PinInputPrimitive.RootProvider>
>(function PinInputRootProvider({ asChild, children, className, ...props }, ref) {
  return (
    <PinInputPrimitive.RootProvider
      ref={ref}
      asChild={asChild}
      data-slot="pin-input-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    >
      {withHiddenInput(children, asChild)}
    </PinInputPrimitive.RootProvider>
  );
});

const PinInputLabel = forwardRef<
  ComponentRef<typeof PinInputPrimitive.Label>,
  ComponentProps<typeof PinInputPrimitive.Label>
>(function PinInputLabel({ className, ...props }, ref) {
  return (
    <PinInputPrimitive.Label
      ref={ref}
      data-slot="pin-input-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

const PinInputControl = forwardRef<
  ComponentRef<typeof PinInputPrimitive.Control>,
  ComponentProps<typeof PinInputPrimitive.Control>
>(function PinInputControl({ className, ...props }, ref) {
  return (
    <PinInputPrimitive.Control
      ref={ref}
      data-slot="pin-input-control"
      className={clsx(styles.control, normalizeClassName(className))}
      {...props}
    />
  );
});

const PinInputInput = forwardRef<
  ComponentRef<typeof PinInputPrimitive.Input>,
  ComponentProps<typeof PinInputPrimitive.Input>
>(function PinInputInput({ className, ...props }, ref) {
  return (
    <PinInputPrimitive.Input
      ref={ref}
      data-slot="pin-input-input"
      className={clsx(styles.input, normalizeClassName(className))}
      {...props}
    />
  );
});

function PinInputInputs({ className }: { className?: string }) {
  const { items } = usePinInputContext();

  return items.map((index) => <PinInputInput key={index} index={index} className={className} />);
}

function withHiddenInput(children: ReactNode, asChild?: boolean) {
  const hiddenInput = <PinInputPrimitive.HiddenInput data-slot="pin-input-hidden-input" />;

  if (!asChild) {
    return (
      <>
        {children}
        {hiddenInput}
      </>
    );
  }

  const child = Children.only(children) as ReactElement<{ children?: ReactNode }>;

  return cloneElement(child, {}, child.props.children, hiddenInput);
}

function PinInputSeparator({
  className,
  'aria-hidden': ariaHidden = true,
  role = 'presentation',
  children,
  ...props
}: ComponentProps<'span'>) {
  return (
    <span
      data-slot="pin-input-separator"
      aria-hidden={ariaHidden}
      role={role}
      className={clsx(styles.separator, normalizeClassName(className))}
      {...props}
    >
      {children ?? <SeparatorMarkIcon />}
    </span>
  );
}

function usePinInput(props: UsePinInputProps = {}) {
  return usePinInputPrimitive({ placeholder: '', ...props });
}

const PinInput = Object.assign(PinInputRoot, {
  Root: PinInputRoot,
  RootProvider: PinInputRootProvider,
  Label: PinInputLabel,
  Control: PinInputControl,
  Input: PinInputInput,
  Inputs: PinInputInputs,
  Separator: PinInputSeparator,
});

export { PinInput, usePinInput };

@layer moduix.components {
  .root {
    display: inline-flex;
    flex-direction: column;
    align-items: flex-start;
    gap: var(--moduix-pin-input-root-gap, var(--moduix-spacing-2));
    width: var(--moduix-pin-input-width, auto);
    max-width: var(--moduix-pin-input-max-width, none);

    &[data-disabled] {
      opacity: var(--moduix-pin-input-disabled-opacity, var(--moduix-opacity-disabled));
    }
  }

  .label {
    color: var(--moduix-pin-input-label-color, var(--moduix-color-foreground));
    font-size: var(--moduix-pin-input-label-font-size, var(--moduix-text-sm));
    font-weight: var(--moduix-pin-input-label-font-weight, var(--moduix-weight-medium));
    line-height: var(--moduix-pin-input-label-line-height, var(--moduix-line-height-text-sm));
  }

  .control {
    display: inline-flex;
    align-items: center;
    gap: var(--moduix-pin-input-gap, var(--moduix-spacing-2));
  }

  .input {
    box-sizing: border-box;
    flex: none;
    width: var(
      --moduix-pin-input-input-width,
      var(--moduix-pin-input-input-size, var(--moduix-size-md))
    );
    height: var(
      --moduix-pin-input-input-height,
      var(--moduix-pin-input-input-size, var(--moduix-size-md))
    );
    margin: 0;
    border: var(--moduix-pin-input-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-pin-input-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-pin-input-radius, var(--moduix-radius-md));
    padding-block: var(--moduix-pin-input-input-padding-y, 0);
    padding-inline: var(--moduix-pin-input-input-padding-x, 0);
    background-color: var(--moduix-pin-input-bg, var(--moduix-color-background));
    color: var(--moduix-pin-input-color, var(--moduix-color-foreground));
    font: inherit;
    font-size: var(--moduix-pin-input-font-size, var(--moduix-text-lg));
    font-weight: var(--moduix-pin-input-font-weight, var(--moduix-weight-medium));
    line-height: var(--moduix-pin-input-line-height, var(--moduix-line-height-text-lg));
    text-align: center;
    font-variant-numeric: tabular-nums;
    outline: var(
        --moduix-pin-input-focus-ring-width,
        var(
          --moduix-pin-input-border-width,
          var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
        )
      )
      solid transparent;
    outline-offset: var(
      --moduix-pin-input-focus-ring-offset,
      var(--moduix-focus-ring-inset-offset)
    );
    transition:
      border-color var(--moduix-pin-input-transition, var(--moduix-transition-default)),
      outline-color var(--moduix-pin-input-transition, var(--moduix-transition-default)),
      background-color var(--moduix-pin-input-transition, var(--moduix-transition-default));

    &::placeholder {
      color: var(--moduix-pin-input-placeholder-color, var(--moduix-color-muted-foreground));
    }

    &:focus-visible {
      outline-color: var(--moduix-pin-input-focus-ring-color, var(--moduix-color-ring));
    }

    &[data-complete] {
      border-color: var(
        --moduix-pin-input-border-color-complete,
        var(--moduix-pin-input-border-color, var(--moduix-color-border))
      );
    }

    &[data-invalid] {
      border-color: var(--moduix-pin-input-border-color-invalid, var(--moduix-color-destructive));

      &:focus-visible {
        outline-color: var(
          --moduix-pin-input-border-color-invalid,
          var(--moduix-color-destructive)
        );
      }
    }

    &[data-disabled] {
      pointer-events: none;
    }
  }

  .separator {
    display: inline-flex;
    flex: none;
    align-items: center;
    justify-content: center;
    width: var(
      --moduix-pin-input-separator-width,
      var(--moduix-pin-input-separator-size, var(--moduix-spacing-4))
    );
    height: var(
      --moduix-pin-input-separator-height,
      var(--moduix-pin-input-separator-size, var(--moduix-spacing-4))
    );
    color: var(--moduix-pin-input-separator-color, var(--moduix-color-muted-foreground));
    line-height: 1;
    pointer-events: none;

    & > svg {
      width: 100%;
      height: 100%;
      flex: none;
    }
  }
}
